Here's a complete multiplayer VR arena with all requested systems:

```holoscript
meta {
  id: 'ARENA_001'
  name: 'Combat Arena'
  maxPlayers: 8
  physics: 'rapier3d'
  networking: 'websocket-reliable'
}

scene CombatArena @networked {

  environment {
    skybox: 'nebula_hdri'
    ambientLight: 0.15
    fog: { color: '#1a1a2e', density: 0.02 }
  }

  postProcessing {
    bloom: { intensity: 0.8, threshold: 0.6 }
    vignette: 0.3
    colorGrading: 'cyberpunk'
  }

  network {
    tickRate: 60
    interpolation: true
    prediction: true
  }

  // ==========================================
  // GAME STATE
  // ==========================================

  state gamePhase: 'warmup'
  state scores: { alpha: 0, beta: 0 }
  state currentRound: 1
  state timeRemaining: 300
  state killfeed: []

  const config: {
    roundTime: 300
    maxRounds: 3
    scoreToWin: 50
    warmupTime: 30
    respawnTime: 3
  }

  // ==========================================
  // PLAYER TEMPLATE
  // ==========================================

  template PlayerAvatar @networked @collidable {
    model: 'player_rig.glb'

    state health: 100
    state shield: 50
    state team: null
    state equipped: null
    state alive: true

    sync position
    sync rotation
    sync health
    sync shield
    sync team

    // Health regeneration
    on interval 1s {
      if alive and health < 100 and lastDamageTime > 5s {
        set health: min(health + 5, 100)
      }
    }

    function takeDamage(amount, source) {
      // Shield absorbs 70% of damage first
      if shield > 0 {
        let absorbed: min(shield, amount * 0.7)
        set shield: shield - absorbed
        set amount: amount - absorbed
      }

      set health: health - amount
      set lastDamageTime: now()

      // Damage indicator
      spawn particles DamageFlash at self.position {
        color: '#FF0000'
        count: 10
        lifetime: 0.2s
      }

      if health <= 0 {
        call die(source)
      }
    }

    function die(killer) {
      set alive: false

      // Death effects
      play sound 'death.mp3'
      spawn particles DeathExplosion at self.position {
        color: team == 'alpha' ? '#FF4444' : '#4444FF'
        count: 100
        speed: 5
        lifetime: 1s
      }

      // Update killfeed
      sync push { killer: killer.name, victim: self.name, weapon: killer.equipped } to killfeed

      // Award points
      sync set scores[killer.team]: scores[killer.team] + 1

      // Hide and respawn
      set self.visible: false

      after config.respawnTime {
        call respawn()
      }
    }

    function respawn() {
      let spawnPoint: getSpawnPoint(team)
      set self.position: spawnPoint.position
      set health: 100
      set shield: 50
      set alive: true
      set self.visible: true

      spawn particles RespawnEffect at self.position {
        color: '#FFFFFF'
        count: 50
        type: 'burst'
      }
    }

    // Floating health bar
    ui HealthBar {
      position: [0, 2.2, 0]
      size: [0.8, 0.1]
      billboard: true
      visible: alive

      bar Health {
        value: health
        max: 100
        color: '#44FF44'
        background: '#333333'
      }

      bar Shield {
        position: [0, -0.12, 0]
        value: shield
        max: 100
        color: '#4488FF'
        background: '#222244'
      }

      text TeamTag {
        position: [0, 0.15, 0]
        content: '{self.name}'
        color: team == 'alpha' ? '#FF6666' : '#6666FF'
        fontSize: 14
      }
    }
  }

  // ==========================================
  // WEAPON SYSTEM
  // ==========================================

  template Weapon @grabbable @networked {
    state owner: null
    state ammo: 0
    state fireMode: 'primary'

    sync owner
    sync ammo

    on grab by player {
      if requestOwnership() {
        set owner: player.id
        set player.equipped: self.id
        play sound 'weapon_pickup.mp3'
      }
    }

    on release {
      set owner: null
    }

    // Toggle fire mode with grip button
    on grip {
      set fireMode: fireMode == 'primary' ? 'secondary' : 'primary'
      play sound 'mode_switch.mp3'
    }
  }

  object PlasmaPistol extends Weapon {
    model: 'plasma_pistol.glb'
    position: [5, 1, 0]

    state ammo: 30

    const stats: {
      primary: { damage: 15, fireRate: 200, speed: 50, color: '#00FFFF' }
      secondary: { damage: 40, fireRate: 800, speed: 30, color: '#FF00FF', burst: 3 }
    }

    on trigger {
      if ammo <= 0 {
        play sound 'empty_clip.mp3'
        return
      }

      let mode: stats[fireMode]

      if fireMode == 'secondary' {
        // Burst fire
        repeat mode.burst as i {
          after i * 100ms {
            call fireProjectile(mode)
          }
        }
        set ammo: ammo - mode.burst
      } else {
        call fireProjectile(mode)
        set ammo: ammo - 1
      }
    }

    function fireProjectile(mode) {
      spawn PlasmaProjectile at muzzle.worldPosition {
        velocity: muzzle.forward * mode.speed
        damage: mode.damage
        owner: owner
        color: mode.color
      }

      spawn particles MuzzleFlash at muzzle.worldPosition {
        color: mode.color
        count: 20
        speed: 10
        lifetime: 0.1s
      }

      play sound 'plasma_fire.mp3' at self.position
    }
  }

  object QuantumRifle extends Weapon {
    model: 'quantum_rifle.glb'
    position: [-5, 1, 0]

    state chargeLevel: 0
    state isCharging: false

    const stats: {
      primary: { damage: 25, fireRate: 400 }  // Rapid hitscan
      secondary: { damage: 100, chargeTime: 1.5 }  // Charged shot
    }

    on trigger down {
      if fireMode == 'secondary' {
        set isCharging: true
        set chargeLevel: 0

        // Charge visual
        play animation ChargeGlow
        play sound 'charge_start.mp3'
      }
    }

    on frame {
      if isCharging {
        set chargeLevel: min(chargeLevel + deltaTime / stats.secondary.chargeTime, 1)

        // Charging particles
        spawn particles ChargeParticle at muzzle.worldPosition {
          color: lerp('#4444FF', '#FF44FF', chargeLevel)
          count: 1
          velocity: (muzzle.worldPosition - self.position) * -2
        }
      }
    }

    on trigger up {
      if fireMode == 'primary' {
        // Rapid hitscan
        let hit: raycast(muzzle.worldPosition, muzzle.forward, 100)
        if hit.entity and hit.entity.takeDamage {
          hit.entity.takeDamage(stats.primary.damage, getPlayer(owner))
        }

        // Tracer visual
        spawn object Tracer {
          geometry: 'line'
          from: muzzle.worldPosition
          to: hit.point or muzzle.worldPosition + muzzle.forward * 100
          color: '#AAAAFF'
          lifetime: 0.1s
        }
      } else if isCharging {
        // Release charged shot
        set isCharging: false

        let damage: stats.secondary.damage * chargeLevel
        let hit: raycast(muzzle.worldPosition, muzzle.forward, 200)

        if hit.entity and hit.entity.takeDamage {
          hit.entity.takeDamage(damage, getPlayer(owner))
        }

        // Beam visual
        spawn object ChargedBeam {
          geometry: 'cylinder'
          from: muzzle.worldPosition
          to: hit.point or muzzle.worldPosition + muzzle.forward * 200
          radius: 0.05 + chargeLevel * 0.1
          color: '#FF44FF'
          emissive: '#FF00FF'
          lifetime: 0.3s
        }

        play sound 'quantum_fire.mp3'
        set chargeLevel: 0
      }
    }
  }

  // Projectile template
  template PlasmaProjectile @networked {
    geometry: 'sphere'
    scale: 0.1
    emissive: '{self.color}'

    state damage: 0
    state owner: null

    physics: { mass: 0.1 }

    particles Trail {
      color: '{self.color}'
      count: 5
      lifetime: 0.3s
      type: 'trail'
    }

    on collide with entity {
      if entity.id != owner and entity.takeDamage {
        entity.takeDamage(damage, getPlayer(owner))
      }

      spawn particles Impact at self.position {
        color: '{self.color}'
        count: 30
        speed: 8
        lifetime: 0.3s
      }

      destroy self
    }

    after 3s {
      destroy self
    }
  }

  // ==========================================
  // PICKUP SYSTEM
  // ==========================================

  template Pickup @interactable @networked {
    state active: true
    state respawnTime: 15

    sync active

    visible: active

    animation Float {
      property: 'position.y'
      from: self.position[1]
      to: self.position[1] + 0.3
      duration: 1.5s
      loop: infinite
      direction: alternate
    }

    animation Spin {
      property: 'rotation.y'
      from: 0
      to: 360
      duration: 3s
      loop: infinite
    }

    on click by player {
      if not active { return }

      call applyEffect(player)

      sync set active: false
      play sound 'pickup.mp3'

      spawn particles PickupEffect at self.position {
        color: '{self.glowColor}'
        count: 40
        type: 'burst'
      }

      after respawnTime {
        sync set active: true
        spawn particles RespawnEffect at self.position {
          color: '#FFFFFF'
          count: 20
        }
      }
    }
  }

  object HealthPack extends Pickup {
    model: 'health_pack.glb'
    position: [0, 1, 5]
    glowColor: '#44FF44'
    respawnTime: 20

    light Glow {
      type: 'point'
      color: '#44FF44'
      intensity: 1
      distance: 3
    }

    function applyEffect(player) {
      set player.health: min(player.health + 50, 100)
      notify player '+50 Health'
    }
  }

  object ShieldBoost extends Pickup {
    model: 'shield_orb.glb'
    position: [0, 1, -5]
    glowColor: '#4488FF'
    respawnTime: 25

    light Glow {
      type: 'point'
      color: '#4488FF'
      intensity: 1
      distance: 3
    }

    function applyEffect(player) {
      set player.shield: min(player.shield + 50, 100)
      notify player '+50 Shield'
    }
  }

  object AmmoCache extends Pickup {
    model: 'ammo_crate.glb'
    position: [8, 1, 0]
    glowColor: '#FFAA00'
    respawnTime: 15

    function applyEffect(player) {
      if player.equipped {
        let weapon: getObject(player.equipped)
        set weapon.ammo: weapon.ammo + 30
        notify player '+30 Ammo'
      }
    }
  }

  object SpeedBoost extends Pickup {
    model: 'speed_orb.glb'
    position: [-8, 1, 0]
    glowColor: '#FFFF00'
    respawnTime: 30

    function applyEffect(player) {
      apply effect 'speed' to player {
        multiplier: 1.5
        duration: 10s
      }
      notify player 'Speed Boost - 10s'
    }
  }

  // ==========================================
  // GAME MANAGER
  // ==========================================

  controller GameManager @networked {

    stateMachine GameFlow {
      initial: 'warmup'

      states: {
        warmup: {
          enter: {
            sync set gamePhase: 'warmup'
            sync set timeRemaining: config.warmupTime
            broadcast 'Match starting in {config.warmupTime} seconds...'
          }

          on interval 1s {
            sync set timeRemaining: timeRemaining - 1
          }

          transitions: {
            start: { when: timeRemaining <= 0, to: 'playing' }
          }
        }

        playing: {
          enter: {
            sync set gamePhase: 'playing'
            sync set timeRemaining: config.roundTime
            broadcast 'Round {currentRound} - FIGHT!'
          }

          on interval 1s {
            sync set timeRemaining: timeRemaining - 1
          }

          transitions: {
            timeUp: { when: timeRemaining <= 0, to: 'roundEnd' }
            scoreReached: { when: scores.alpha >= config.scoreToWin or scores.beta >= config.scoreToWin, to: 'roundEnd' }
          }
        }

        roundEnd: {
          enter: {
            sync set gamePhase: 'roundEnd'

            let winner: scores.alpha > scores.beta ? 'Alpha' : 'Beta'
            broadcast 'Round Over! {winner} Team wins!'
          }

          after 5s: {
            if currentRound >= config.maxRounds {
              transition to 'gameOver'
            } else {
              sync set currentRound: currentRound + 1
              sync set scores: { alpha: 0, beta: 0 }
              transition to 'playing'
            }
          }
        }

        gameOver: {
          enter: {
            sync set gamePhase: 'gameOver'

            let winner: scores.alpha > scores.beta ? 'Alpha' : 'Beta'
            broadcast 'GAME OVER! {winner} Team Wins The Match!'

            show GameOverOverlay
          }

          after 15s: {
            // Return to lobby or restart
            call resetMatch()
            transition to 'warmup'
          }
        }
      }
    }

    function resetMatch() {
      sync set currentRound: 1
      sync set scores: { alpha: 0, beta: 0 }
      sync set killfeed: []

      // Respawn all players
      for player in getPlayers() {
        player.respawn()
      }

      // Reset pickups
      for pickup in getObjectsWithTrait(@Pickup) {
        sync set pickup.active: true
      }
    }
  }

  // ==========================================
  // SPAWN POINTS
  // ==========================================

  object SpawnAlpha1 @spawn { position: [-10, 0, -10] team: 'alpha' }
  object SpawnAlpha2 @spawn { position: [-10, 0, 10] team: 'alpha' }
  object SpawnBeta1 @spawn { position: [10, 0, -10] team: 'beta' }
  object SpawnBeta2 @spawn { position: [10, 0, 10] team: 'beta' }

  function getSpawnPoint(team) {
    let spawns: getObjectsWithTrait(@spawn).filter(s => s.team == team)
    return spawns[random(0, spawns.length - 1)]
  }

  // ==========================================
  // UI SYSTEM
  // ==========================================

  ui GameHUD {
    anchor: 'screen'

    // Timer
    panel TimerPanel {
      position: [0.5, 0.95, 0]
      size: [0.15, 0.06]
      style: { background: '#000000AA', borderRadius: 8 }

      text Timer {
        content: '{formatTime(timeRemaining)}'
        color: timeRemaining <= 30 ? '#FF4444' : '#FFFFFF'
        fontSize: 28
        align: 'center'
      }
    }

    // Scores
    panel ScorePanel {
      position: [0.5, 0.88, 0]
      size: [0.3, 0.05]
      style: { background: '#00000088' }

      text AlphaScore {
        position: [0.3, 0.5, 0]
        content: 'ALPHA: {scores.alpha}'
        color: '#FF6666'
        fontSize: 20
      }

      text BetaScore {
        position: [0.7, 0.5, 0]
        content: 'BETA: {scores.beta}'
        color: '#6666FF'
        fontSize: 20
      }
    }

    // Killfeed
    list Killfeed {
      position: [0.95, 0.75, 0]
      anchor: 'top-right'
      size: [0.25, 0.3]
      maxItems: 5
      itemDuration: 4000
      data: killfeed

      template KillfeedItem {
        style: { background: '#00000088', padding: 4 }

        text Content {
          content: '{item.killer} ⚔ {item.victim}'
          fontSize: 14
          color: '#FFFFFF'
        }
      }
    }

    // Local player health (bottom center)
    panel LocalHealth {
      position: [0.5, 0.08, 0]
      size: [0.3, 0.06]
      anchor: 'bottom'
      style: { background: '#00000088', borderRadius: 8 }

      bar HealthBar {
        position: [0.5, 0.6, 0]
        size: [0.9, 0.35]
        value: localPlayer.health
        max: 100
        color: '#44FF44'
        background: '#333333'

        text Label {
          content: '{localPlayer.health}'
          color: '#FFFFFF'
          fontSize: 16
        }
      }

      bar ShieldBar {
        position: [0.5, 0.25, 0]
        size: [0.9, 0.2]
        value: localPlayer.shield
        max: 100
        color: '#4488FF'
        background: '#222244'
      }
    }

    // Ammo display
    panel AmmoPanel {
      position: [0.85, 0.08, 0]
      size: [0.1, 0.06]
      anchor: 'bottom-right'
      style: { background: '#00000088' }
      visible: localPlayer.equipped != null

      text Ammo {
        content: '{getObject(localPlayer.equipped)?.ammo ?? 0}'
        color: '#FFAA00'
        fontSize: 24
        align: 'center'
      }

      text Label {
        position: [0.5, 0.2, 0]
        content: 'AMMO'
        color: '#888888'
        fontSize: 10
      }
    }

    // Round indicator
    text RoundIndicator {
      position: [0.5, 0.82, 0]
      content: 'ROUND {currentRound}/{config.maxRounds}'
      color: '#888888'
      fontSize: 14
    }

    // Game phase announcements
    text PhaseAnnouncement {
      position: [0.5, 0.5, 0]
      content: ''
      color: '#FFFFFF'
      fontSize: 48
      visible: gamePhase == 'warmup' or gamePhase == 'roundEnd'

      content: gamePhase == 'warmup' ? 'MATCH STARTING IN {timeRemaining}' 
             : gamePhase == 'roundEnd' ? 'ROUND OVER'
             : ''
    }
  }

  // Game over overlay
  ui GameOverOverlay {
    anchor: 'screen'
    visible: gamePhase == 'gameOver'
    style: { background: '#000000CC' }

    text Winner {
      position: [0.5, 0.4, 0]
      content: scores.alpha > scores.beta ? 'ALPHA TEAM WINS!' : 'BETA TEAM WINS!'
      color: scores.alpha > scores.beta ? '#FF4444' : '#4444FF'
      fontSize: 64
      align: 'center'
    }

    text FinalScore {
      position: [0.5, 0.55, 0]
      content: 'Final Score: {scores.alpha} - {scores.beta}'
      color: '#FFFFFF'
      fontSize: 32
    }

    text Restart {
      position: [0.5, 0.7, 0]
      content: 'New match starting in 15 seconds...'
      color: '#888888'
      fontSize: 18
    }
  }

  // ==========================================
  // ARENA ENVIRONMENT
  // ==========================================

  // Floor
  object ArenaFloor @collidable {
    geometry: 'plane'
    position: [0, 0, 0]
    rotation: [-90, 0, 0]
    scale: 50
    material: {
      texture: 'arena_floor.jpg'
      roughness: 0.6
      metalness: 0.2
    }
  }

  // Cover objects
  repeat 8 as i {
    object Cover_{i} @collidable {
      geometry: 'box'
      position: [cos(i * 45deg) * 8, 1, sin(i * 45deg) * 8]
      scale: [2, 2, 0.5]
      rotation: [0, i * 45, 0]
      material: {
        color: '#444444'
        roughness: 0.8
        metalness: 0.3
      }
    }
  }

  // Central structure
  object CentralPlatform @collidable {
    geometry: 'cylinder'
    position: [0, 0.5, 0]
    scale: [4, 1, 4]
    material: {
      color: '#222233'
      emissive: '#110022'
      roughness: 0.4
    }
  }

  // Arena lighting
  light MainLight {
    type: 'directional'
    position: [10, 20, 10]
    color: '#FFFFFF'
    intensity: 0.8
    castShadow: true
  }

  repeat 4 as i {
    light ArenaLight_{i} {
      type: 'point'
      position: [cos(i * 90deg) * 15, 8, sin(i * 90deg) * 15]
      color: i % 2 == 0 ? '#FF4444' : '#4444FF'
      intensity: 2
      distance: 20
    }
  }

  // Helper functions
  function formatTime(seconds) {
    let mins: floor(seconds / 60)
    let secs: seconds % 60
    return '{mins}:{secs < 10 ? "0" : ""}{secs}'
  }
}
```

**Systems included**:
- **Networking**: 60Hz with interpolation and prediction
- **Players**: Health/shield, regeneration, death/respawn, team colors
- **Weapons**: Plasma pistol (rapid/burst modes), Quantum rifle (hitscan/charged)
- **Pickups**: Health, shield, ammo, speed boost with respawn
- **Game flow**: Warmup → rounds → game over with full state machine
- **UI**: Timer, scores, killfeed, health bars, ammo, announcements
- **Visuals**: Particles, lighting, materials, post-processing

Here's a complete RPG inventory system:

```holoscript
scene InventoryDemo @networked {

  // ==========================================
  // ITEM DEFINITIONS
  // ==========================================

  const RARITIES: {
    common: { color: '#AAAAAA', multiplier: 1.0 }
    uncommon: { color: '#55FF55', multiplier: 1.2 }
    rare: { color: '#5555FF', multiplier: 1.5 }
    epic: { color: '#AA55FF', multiplier: 2.0 }
    legendary: { color: '#FFAA00', multiplier: 3.0 }
  }

  const ITEM_DATABASE: {
    // Weapons
    iron_sword: {
      name: 'Iron Sword'
      type: 'weapon'
      slot: 'weapon'
      stackable: false
      rarity: 'common'
      stats: { damage: 10, speed: 1.0 }
      icon: 'icons/iron_sword.png'
      sellValue: 25
    }
    flame_blade: {
      name: 'Flame Blade'
      type: 'weapon'
      slot: 'weapon'
      stackable: false
      rarity: 'epic'
      stats: { damage: 35, speed: 1.2, fireDamage: 15 }
      icon: 'icons/flame_blade.png'
      sellValue: 500
    }

    // Armor
    leather_helm: {
      name: 'Leather Helm'
      type: 'armor'
      slot: 'head'
      stackable: false
      rarity: 'common'
      stats: { defense: 5 }
      icon: 'icons/leather_helm.png'
      sellValue: 15
    }
    dragon_plate: {
      name: 'Dragon Plate'
      type: 'armor'
      slot: 'chest'
      stackable: false
      rarity: 'legendary'
      stats: { defense: 50, fireResist: 30, health: 100 }
      icon: 'icons/dragon_plate.png'
      sellValue: 2000
    }

    // Consumables
    health_potion: {
      name: 'Health Potion'
      type: 'consumable'
      stackable: true
      maxStack: 20
      rarity: 'common'
      effect: { heal: 50 }
      icon: 'icons/health_potion.png'
      sellValue: 10
    }
    mana_potion: {
      name: 'Mana Potion'
      type: 'consumable'
      stackable: true
      maxStack: 20
      rarity: 'common'
      effect: { mana: 50 }
      icon: 'icons/mana_potion.png'
      sellValue: 10
    }

    // Materials
    iron_ore: {
      name: 'Iron Ore'
      type: 'material'
      stackable: true
      maxStack: 99
      rarity: 'common'
      icon: 'icons/iron_ore.png'
      sellValue: 5
    }
    dragon_scale: {
      name: 'Dragon Scale'
      type: 'material'
      stackable: true
      maxStack: 50
      rarity: 'epic'
      icon: 'icons/dragon_scale.png'
      sellValue: 100
    }
  }

  const RECIPES: {
    iron_sword: {
      materials: { iron_ore: 5 }
      result: { item: 'iron_sword', count: 1 }
      craftTime: 2
    }
    health_potion: {
      materials: { herb: 2, water: 1 }
      result: { item: 'health_potion', count: 3 }
      craftTime: 1
    }
    dragon_plate: {
      materials: { dragon_scale: 10, iron_ore: 20, fire_essence: 5 }
      result: { item: 'dragon_plate', count: 1 }
      craftTime: 10
    }
  }

  // ==========================================
  // PLAYER INVENTORY STATE
  // ==========================================

  state inventory: []  // Array of { itemId, count, slotIndex }
  state equipment: {
    head: null
    chest: null
    hands: null
    feet: null
    weapon: null
  }
  state gold: 100
  state inventorySize: 24

  state draggedItem: null
  state draggedFrom: null
  state showTooltip: false
  state tooltipItem: null
  state tooltipPosition: [0, 0]

  // ==========================================
  // INVENTORY FUNCTIONS
  // ==========================================

  function addItem(itemId, count: 1) {
    let itemDef: ITEM_DATABASE[itemId]

    if itemDef.stackable {
      // Find existing stack
      let existing: inventory.find(i => i.itemId == itemId and i.count < itemDef.maxStack)

      if existing {
        let space: itemDef.maxStack - existing.count
        let toAdd: min(count, space)
        set existing.count: existing.count + toAdd
        count -= toAdd
      }
    }

    // Add new stacks
    while count > 0 {
      let emptySlot: findEmptySlot()
      if emptySlot == -1 {
        notify player 'Inventory full!'
        return false
      }

      let stackSize: itemDef.stackable ? min(count, itemDef.maxStack) : 1
      push { itemId: itemId, count: stackSize, slotIndex: emptySlot } to inventory
      count -= stackSize
    }

    play sound 'item_pickup.mp3'
    return true
  }

  function removeItem(itemId, count: 1) {
    let remaining: count

    for slot in inventory.filter(i => i.itemId == itemId).reverse() {
      if remaining <= 0 { break }

      if slot.count <= remaining {
        remaining -= slot.count
        remove slot from inventory
      } else {
        set slot.count: slot.count - remaining
        remaining = 0
      }
    }

    return remaining == 0
  }

  function getItemCount(itemId) {
    return inventory
      .filter(i => i.itemId == itemId)
      .reduce((sum, i) => sum + i.count, 0)
  }

  function findEmptySlot() {
    repeat inventorySize as i {
      if not inventory.find(item => item.slotIndex == i) {
        return i
      }
    }
    return -1
  }

  function equipItem(slot) {
    let item: inventory.find(i => i.slotIndex == slot.slotIndex)
    if not item { return }

    let itemDef: ITEM_DATABASE[item.itemId]
    if not itemDef.slot { return }  // Can't equip non-equipment

    let targetSlot: itemDef.slot

    // Swap with currently equipped
    let currentEquip: equipment[targetSlot]
    if currentEquip {
      set item.itemId: currentEquip
      set item.count: 1
    } else {
      remove item from inventory
    }

    set equipment[targetSlot]: item.itemId

    call recalculateStats()
    play sound 'equip.mp3'
  }

  function unequipItem(slotName) {
    let itemId: equipment[slotName]
    if not itemId { return }

    if not addItem(itemId, 1) {
      notify player 'Inventory full!'
      return
    }

    set equipment[slotName]: null
    call recalculateStats()
  }

  function recalculateStats() {
    let totalStats: { damage: 0, defense: 0, health: 0, speed: 1 }

    for slotName in ['head', 'chest', 'hands', 'feet', 'weapon'] {
      let itemId: equipment[slotName]
      if itemId {
        let itemDef: ITEM_DATABASE[itemId]
        let rarity: RARITIES[itemDef.rarity]

        for stat in Object.keys(itemDef.stats) {
          totalStats[stat] += itemDef.stats[stat] * rarity.multiplier
        }
      }
    }

    set player.bonusStats: totalStats
  }

  function useItem(slot) {
    let item: inventory.find(i => i.slotIndex == slot.slotIndex)
    if not item { return }

    let itemDef: ITEM_DATABASE[item.itemId]

    if itemDef.type == 'consumable' {
      // Apply effect
      if itemDef.effect.heal {
        set player.health: min(player.health + itemDef.effect.heal, player.maxHealth)
        notify player '+{itemDef.effect.heal} Health'
      }
      if itemDef.effect.mana {
        set player.mana: min(player.mana + itemDef.effect.mana, player.maxMana)
        notify player '+{itemDef.effect.mana} Mana'
      }

      // Remove one from stack
      set item.count: item.count - 1
      if item.count <= 0 {
        remove item from inventory
      }

      play sound 'consume.mp3'
    } else if itemDef.slot {
      call equipItem(slot)
    }
  }

  function sellItem(slotIndex, count: 1) {
    let item: inventory.find(i => i.slotIndex == slotIndex)
    if not item { return }

    let itemDef: ITEM_DATABASE[item.itemId]
    let sellCount: min(count, item.count)
    let earnings: sellCount * itemDef.sellValue

    set item.count: item.count - sellCount
    if item.count <= 0 {
      remove item from inventory
    }

    set gold: gold + earnings

    notify player 'Sold for {earnings} gold'
    play sound 'coin.mp3'
  }

  function canCraft(recipeId) {
    let recipe: RECIPES[recipeId]
    if not recipe { return false }

    for material in Object.keys(recipe.materials) {
      if getItemCount(material) < recipe.materials[material] {
        return false
      }
    }
    return true
  }

  function craftItem(recipeId) {
    let recipe: RECIPES[recipeId]

    if not canCraft(recipeId) {
      notify player 'Missing materials!'
      return
    }

    // Remove materials
    for material in Object.keys(recipe.materials) {
      removeItem(material, recipe.materials[material])
    }

    // Add result
    addItem(recipe.result.item, recipe.result.count)

    notify player 'Crafted {ITEM_DATABASE[recipe.result.item].name}!'
    play sound 'craft.mp3'
  }

  // ==========================================
  // INVENTORY UI
  // ==========================================

  ui InventoryPanel {
    position: [0.5, 0.5, 0]
    size: [0.6, 0.7]
    anchor: 'center'
