        equipped: equipment.weapon
        placeholder: '⚔️'
      }
    }

    // Inventory grid
    panel InventoryGrid {
      position: [0.65, 0.45, 0]
      size: [0.6, 0.7]

      grid {
        columns: 6
        rows: 4
        cellSize: [0.14, 0.14]
        gap: 4

        repeat inventorySize as i {
          slot InventorySlot_{i} {
            slotIndex: i
            item: inventory.find(item => item.slotIndex == i)

            style: {
              background: '#2a2a4e'
              border: '1px solid #4a4a6a'
              borderRadius: 4
            }

            // Item display
            if item {
              image Icon {
                src: ITEM_DATABASE[item.itemId].icon
