      on click {
        call useItem(contextTarget)
        hide ContextMenu
      }
    }

    button Sell {
      text: 'Sell'
      on click {
        call sellItem(contextTarget.slotIndex)
        hide ContextMenu
      }
    }

    button Drop {
      text: 'Drop'
