  state relationships: {}  // { npcId: number }
  state reputation: { town: 0, guild: 0, outlaws: 0 }
  state activeQuests: []
  state completedQuests: []
  state dialogueCooldowns: {}  // { npcId: timestamp }

  // Active dialogue state
  state inDialogue: false
  state currentDialogue: null
  state currentNode: null
  state currentSpeaker: null
  state subtitleText: ''
  state isVoicePlaying: false

  // ==========================================
  // NPC TEMPLATE
  // ==========================================

  template NPC @interactable @networked {
    state dialogueTreeId: null
    state currentEmotion: 'neutral'
    state isTalking: false

    // Emotion animations
    animations: {
      neutral: 'idle'
      friendly: 'smile'
      worried: 'nervous'
      angry: 'angry_idle'
      grateful: 'bow'
      proud: 'chest_puff'
      overjoyed: 'celebrate'
      sad: 'slouch'
