    on player within 3m {
      look at player smoothly: 0.5
    }

    // Emotion change
    on currentEmotion change as emotion {
      let animName: animations[emotion] or 'idle'
      play animation animName crossfade: 0.3
    }
  }

  // ==========================================
  // DIALOGUE FUNCTIONS
  // ==========================================

  function startDialogue(npc) {
    let tree: DIALOGUE_TREES[npc.dialogueTreeId]
    if not tree {
      notify player '{npc.name} has nothing to say.'
      return
    }

    set inDialogue: true
    set currentDialogue: tree
    set currentSpeaker: npc

    // Find starting node (check conditions)
    let startNode: findValidStartNode(tree, npc)
    call showNode(startNode)

    // Camera focus
    animate camera to {
      position: npc.position + [0, 1.5, 2]
      lookAt: npc.position + [0, 1.5, 0]
    } duration: 0.5s

    // Show dialogue UI
    show DialogueUI
  }

  function findValidStartNode(tree, npc) {
    // Check for conditional nodes first (like quest completion)
    for nodeId in Object.keys(tree.nodes) {
      let node: tree.nodes[nodeId]
      if node.condition {
        if evaluateCondition(node.condition) {
          return nodeId
        }
      }
    }
    return 'start'
  }

  function evaluateCondition(condition) {
    if condition.quest {
      if condition.status == 'complete' {
        return completedQuests.includes(condition.quest)
      }
      if condition.status == 'active' {
        return activeQuests.find(q => q.id == condition.quest)
      }
    }
    if condition.relationship {
      return relationships[condition.npc] >= condition.minValue
    }
    if condition.reputation {
      return reputation[condition.faction] >= condition.minValue
    }
    return false
  }

  function showNode(nodeId) {
    let node: currentDialogue.nodes[nodeId]
    if not node {
      call endDialogue()
      return
    }

    set currentNode: node
    set subtitleText: ''

    // Set NPC emotion
    if node.emotion {
      // Handle emotion transitions (e.g., 'annoyed' -> 'resigned')
      if node.emotion includes '->' {
        let emotions: node.emotion.split(' -> ')
        set currentSpeaker.currentEmotion: emotions[0]
        after 1.5s {
          set currentSpeaker.currentEmotion: emotions[1]
        }
      } else {
        set currentSpeaker.currentEmotion: node.emotion
      }
    }

    // Play voice line with typewriter subtitles
    if node.voice {
      call playVoiceLine(node.voice, node.text)
    } else {
      call typewriterText(node.text)
    }

    // Handle quest markers
    if node.questMarker {
      show QuestMarker at node.questMarker.target
    }
  }

  function playVoiceLine(audioFile, text) {
    set isVoicePlaying: true

    play sound audioFile {
      on timeupdate as time {
        // Sync subtitles with audio (approximate word timing)
        let progress: time / audioDuration
        let charCount: floor(text.length * progress)
        set subtitleText: text.substring(0, charCount)
      }

      on end {
        set subtitleText: text
        set isVoicePlaying: false
      }
    }
  }

  function typewriterText(text) {
    let charIndex: 0

    timer TypewriterTimer interval: 30ms {
      charIndex++
      set subtitleText: text.substring(0, charIndex)

      if charIndex >= text.length {
        stop timer TypewriterTimer
      }
    }
  }

  function selectChoice(choice) {
    // Apply relationship change
    if choice.relationship {
      let currentRel: relationships[currentSpeaker.id] or 0
      set relationships[currentSpeaker.id]: currentRel + choice.relationship
    }

    // Handle actions
    if choice.action {
      call handleAction(choice)
    }

    // Navigate to next node
    if choice.next {
      call showNode(choice.next)
    } else if choice.action == 'end' {
      call endDialogue()
    }
  }

  function handleAction(choice) {
    switch choice.action {
      case 'end':
        call endDialogue()
        break

      case 'openShop':
        show ShopUI
        set shopData: SHOPS[choice.shopId]
        break

      case 'shopOnly':
        call endDialogue()
        show ShopUI
        set shopData: SHOPS[currentDialogue.nodes[currentNode].shopId]
        break

      case 'startQuest':
        call startQuest(choice.questId)
        break

      case 'completeQuest':
        call completeQuest(currentNode)
        break

      case 'applyDiscount':
        set shopDiscount: currentNode.discount
        break
    }
  }

  function startQuest(questId) {
