    push {
      id: questId
      name: quest.name
      description: quest.description
      objectives: quest.objectives
      progress: {}
    } to activeQuests

    notify player 'Quest Started: {quest.name}'
    play sound 'quest_start.mp3'
  }

  function completeQuest(node) {
    // Give rewards
    for reward in node.rewards {
      switch reward.type {
        case 'item':
          addItem(reward.id, reward.count)
          break
        case 'gold':
          set gold: gold + reward.amount
          break
        case 'reputation':
          set reputation[reward.faction]: reputation[reward.faction] + reward.amount
          break
      }
    }

    // Move quest to completed
    let quest: activeQuests.find(q => q.id == currentNode.questId)
    remove quest from activeQuests
    push quest.id to completedQuests

    notify player 'Quest Complete!'
    play sound 'quest_complete.mp3'
  }

  function endDialogue() {
    set inDialogue: false
    set currentDialogue: null
    set currentNode: null
    set currentSpeaker.currentEmotion: 'neutral'
    set currentSpeaker: null

